(window.webpackJsonp=window.webpackJsonp||[]).push([[412],{1039:function(t,r){t.exports='\x3c!-- \r\ntitle: Git\r\nsort: \r\n--\x3e \r\n# Git教程\r\n\r\n## 创建目录\r\n\r\n```bash\r\nmd git_study\t\r\ncd .\\git_sudy\t# 新建文件夹并进入\r\n\r\ngit init\t\t# 初始化git仓库\r\necho 123456 > 1.txt\t# 写入东西\r\n\r\ngit add .\\1.txt\t\t# 添加至缓冲区\r\ngit commit -m "添加了1.txt"\t# 添加至归档区\r\n# 进入github新建仓库\r\n# 如果使用代理，执行如下两条\r\n# git config --global http.proxy 127.0.0.1:port\r\n# git config --global https.proxy 127.0.0.1:port\r\n# 取消\r\n# git config --global --unset http.proxy\r\ngit remote add origin https://github.com/fzf404/gitdemo.git\t# 添加仓库地址\r\n\r\n\r\n```\r\n\r\n# SSH\r\n\r\n```bash\r\nssh-keygen.exe\r\n# 复制id_rsa.pub到Delpoy keys\r\ngit push -u origin master\t\t# push一下commit\r\n# 如果需要输入密码，执行下面命令\r\n# git config --global credential.helper store\r\n\r\n# 更新ssh\r\ngit remote rm origin\t\r\ngit push --set-upstream origin master\r\ngit remote add origin git@github.com:fzf404/Tech_Note.git\r\n```\r\n\r\n## 更多命令\r\n\r\n```bash\r\ngit status\t\t# 显示当前状态\r\ngit add . \t\t# 添加所有文件\r\ngit commit -m "two commit"\r\ngit log\t\t\t# 查看过去操作\r\ngit reflog\t\t# 查看操作记录\r\n\r\ngit reset <>\t# 归档区回滚\r\n\t--mixed\t\t# (默认)回滚归档区与缓冲区\r\n\t--hard\t\t# 回滚三个区\r\n\t--soft\t\t# 回滚归档去\r\ngit reset HEAD <file>\t# 撤销add文件\r\ngit checkout --<file>\t# 撤销工作区的修改\r\n\r\ngit revert <>\t# 抹除某次提交\r\n\r\ngit remote -v\t# 查看服务端地址\r\ngit remote remove origin\t# 删除重新添加\r\ngit remote add origin git@github.com:fzf404/gitdemo.git\r\n```\r\n\r\n## 创建分支\r\n\r\n```bash\r\ngit branch -v\t# 查看当前分支\r\ngit checkout -b b1\t# 新建分支并切换\r\n# 合并分支\r\ngit checkout master\t# 回到主分支\r\ngit merge b1\t\t# 合并但不删除\r\n# 遇到冲突可将master合并并修改冲突\r\ngit pull\t\t\t# 拉取远端仓库的最新版本并合并\r\n# 相当于如下指令的结合\r\n# fetch/merge\r\n```\r\n\r\n## 忽略文件\r\n\r\n> 以斜杠`/`开头表示目录；\r\n> 以星号`*`通配多个字符；\r\n> 以问号`?`通配单个字符；\r\n> 以方括号`[]`包含单个字符的匹配列表；\r\n> 以叹号`!`表示不忽略(跟踪)匹配到的文件或目录；\r\n\r\n```\r\n/mtk/ 过滤整个文件夹\r\n*.zip 过滤所有.zip文件\r\n/mtk/do.c 过滤某个具体文件\r\n```\r\n\r\n## GItee\r\n\r\n> github 与 gitee 同步更新\r\n\r\n```bash\r\n# 删除已关联名为origin的远程库\r\ngit remote rm origin\t\r\n# 关联 github 与 gitee\r\ngit remote add github git@github.com:\r\ngit remote add gitee git@gitee.com:\r\n# 检查\r\ngit remote -v\r\n# 上传\r\ngit push github master\r\ngit push gitee master\r\n# 修改配置文件\r\nnotepad .\\.git\\config\r\n```\r\n'}}]);